// ── 8. ОТСЛЕЖИВАНИЕ СКРОЛЛА (ПОЯВЛЕНИЕ СТОЛА КАК НА РЕФЕРЕНСЕ) ──
let scrollProgress = 0

// Easing function для плавности
const easeInOutCubic = (x: number): number => {
   return x < 0.5 ? 4 * x * x * x : 1 - Math.pow(-2 * x + 2, 3) / 2
}

const onScroll = () => {
   const aboutEl = document.getElementById('about')
   if (!aboutEl) return

   const aboutTop = aboutEl.offsetTop
   const transitionZone = aboutTop > 0 ? aboutTop : window.innerHeight

   if (window.scrollY <= transitionZone) {
      // ЗОНА ПЕРЕХОДА: Hero → About (0.0 → 1.0)
      // Применяем easing для плавного появления
      const raw = window.scrollY / transitionZone
      scrollProgress = easeInOutCubic(Math.min(raw, 1.0))
      if (wrapperRef.current) {
         wrapperRef.current.style.top = '0px'
      }
   } else {
      // НИЖЕ секции About: персонаж зафиксирован в сидячей позе
      scrollProgress = 1.0
      if (wrapperRef.current) {
         const overScroll = window.scrollY - transitionZone
         wrapperRef.current.style.top = `-${overScroll}px`
      }
   }
}
window.addEventListener('scroll', onScroll)
onScroll()

